import osimport numpy as npimport pandas as pdimport matplotlib.pyplot as pltfrom joblib import dumpfrom skopt import BayesSearchCVfrom skopt.space import Integerfrom sklearn.ensemble import RandomForestRegressorfrom sklearn.metrics import make_scorer, mean_squared_error# Importações dos seus módulos locaisfrom tratamento_03 import obter_dados_tratados_2dfrom importacao_01 import plots_design# =====================================================================# 1. CONFIGURÁVEIS (Parâmetros Iniciais e Espaço de Busca)# =====================================================================N_ITER_BAYES = 30  # Quantidade de iterações da busca BayesianaCV_FOLDS = 3       # Folds da validação cruzada# --- NOVOS CONFIGURÁVEIS ---USAR_DIFFERENCE_FEATURE = True  # True = FS + DF | False = Apenas FSMETRICA_LOSS = 'phm08'          # Opções: 'mse', 'rmse' ou 'phm08'# Espaço de busca (skopt)OPCOES_N_ESTIMATORS = (50, 500)OPCOES_MAX_DEPTH = (10, 50)OPCOES_MIN_SAMPLES_SPLIT = (2, 10)OPCOES_MIN_SAMPLES_LEAF = (1, 4)# =====================================================================# FUNÇÕES DE LOSS CUSTOMIZADAS (Scikit-Learn Scorers)# =====================================================================def rmse_func(y_true, y_pred):    return np.sqrt(mean_squared_error(y_true, y_pred))def phm08_func(y_true, y_pred):    d = y_pred - y_true    # d < 0: divisor 13 | d >= 0: divisor 10    score = np.where(d < 0, np.exp(-d / 13.0) - 1.0, np.exp(d / 10.0) - 1.0)    return np.mean(score)def selecionar_scorer():    # greater_is_better=False faz o Scikit-Learn tentar minimizar essa função de custo    if METRICA_LOSS.lower() == 'rmse':         return make_scorer(rmse_func, greater_is_better=False)    if METRICA_LOSS.lower() == 'phm08':         return make_scorer(phm08_func, greater_is_better=False)    return 'neg_mean_squared_error' # Padrão nativo do sklearn para MSE# =====================================================================# 2. PLOTS E ANÁLISE DOS HIPERPARÂMETROS# =====================================================================def plotar_efeito_unico(df, hp_name, x_label, filename):    col = f'param_{hp_name}'    if col not in df.columns: return        # O scikit-learn salva os scores como negativos. Multiplicamos por -1 para plotar o erro real.    efeito = -df.groupby(col)['mean_test_score'].mean()        fig, ax = plt.subplots()    ax.plot(efeito.index.astype(str), efeito.values, marker='o', linestyle='-', color='black')        ax.set_xlabel(x_label)    ax.set_ylabel(f"Erro Médio ({METRICA_LOSS.upper()})")        # Aplica o design (tamanho_figura = 2) sem títulos    plots_design(ax, fig=fig, tamanho_figura=2)        plt.savefig(filename, dpi=600, bbox_inches='tight', pad_inches=0.01)    plt.close(fig)def gerar_graficos_rf(bayes_search):    os.makedirs('imagens', exist_ok=True)    df_res = pd.DataFrame(bayes_search.cv_results_)        plotar_efeito_unico(df_res, 'n_estimators', 'Number of estimators', 'imagens/rf_a_estimators.png')    plotar_efeito_unico(df_res, 'max_depth', 'Max depth', 'imagens/rf_b_depth.png')    plotar_efeito_unico(df_res, 'min_samples_split', 'Min samples split', 'imagens/rf_c_samples_split.png')    plotar_efeito_unico(df_res, 'min_samples_leaf', 'Min samples leaf', 'imagens/rf_d_samples_leaf.png')# =====================================================================# 3. EXECUÇÃO PRINCIPAL# =====================================================================if __name__ == "__main__":    # 3.1 Extração e Seleção Dinâmica de Features    estagios = obter_dados_tratados_2d()    df_train = estagios['fs_train']        features = ['FS', 'DF'] if USAR_DIFFERENCE_FEATURE else ['FS']    X_train = df_train[features].values    Y_train = df_train['RUL_CPD'].values        # 3.2 Otimização Bayesiana    param_dist_bayes = {        'n_estimators': Integer(*OPCOES_N_ESTIMATORS),        'max_depth': Integer(*OPCOES_MAX_DEPTH),        'min_samples_split': Integer(*OPCOES_MIN_SAMPLES_SPLIT),        'min_samples_leaf': Integer(*OPCOES_MIN_SAMPLES_LEAF)    }        rf_base = RandomForestRegressor(random_state=42)        bayes_search = BayesSearchCV(        estimator=rf_base,        search_spaces=param_dist_bayes,        n_iter=N_ITER_BAYES,        cv=CV_FOLDS,        scoring=selecionar_scorer(),        random_state=42,        n_jobs=-1,        verbose=1    )        print(f"\n--- Iniciando Otimização Bayesiana (Random Forest) com Loss: {METRICA_LOSS.upper()} ---")    bayes_search.fit(X_train, Y_train)        # 3.3 Salvar Hiperparâmetros em TXT    best_params = bayes_search.best_params_    with open("melhores_hiperparametros_rf.txt", "w", encoding='utf-8') as f:        f.write(f"Melhores Hiperparametros RF (Loss: {METRICA_LOSS.upper()}):\n")        f.write(f"- Difference Feature: {'Ativado' if USAR_DIFFERENCE_FEATURE else 'Desativado'}\n")        for param, value in best_params.items():            f.write(f"- {param}: {value}\n")                print("\n[+] Configurações otimizadas salvas em 'melhores_hiperparametros_rf.txt'.")        # 3.4 Plotagem das análises de influência    gerar_graficos_rf(bayes_search)    print("[+] Gráficos dos efeitos (tamanho 2) salvos na pasta 'imagens/'.")        # 3.5 Salvar modelo otimizado (treinado automaticamente no conjunto completo pelo skopt)    melhor_modelo = bayes_search.best_estimator_    dump(melhor_modelo, 'FD00x_rf_otimizado.joblib')    print("[+] Modelo salvo com sucesso como 'FD00x_rf_otimizado.joblib'!")